import React, { useEffect } from 'react';
import {
  ShoppingCart,
  Plus,
  Minus,
  Trash2,
  LogOut,
  ArrowLeft
} from 'lucide-react';

function CartPage({
  cart = [],
  user,
  setCurrentPage,
  handleLogout,
  updateCartQuantity,
  removeFromCart
}) {
  // Debug logging
  useEffect(() => {
    console.group('🛒 CartPage Debug Info');
    console.log('Cart data:', cart);
    console.log('Cart is array:', Array.isArray(cart));
    console.log('Cart length:', cart?.length);
    console.log('User:', user);
    console.log('Functions available:', {
      updateCartQuantity: typeof updateCartQuantity,
      removeFromCart: typeof removeFromCart,
      setCurrentPage: typeof setCurrentPage,
      handleLogout: typeof handleLogout
    });
    console.groupEnd();
  }, [cart, user]);

  // Validation - ensure cart is an array
  if (!Array.isArray(cart)) {
    console.error('❌ Cart is not an array:', cart);
    return (
      <div className="min-h-screen bg-gradient-to-b from-slate-50 via-white to-slate-50 flex items-center justify-center">
        <div className="text-center p-8">
          <ShoppingCart size={60} className="mx-auto mb-4 text-gray-400" />
          <h2 className="text-xl font-semibold mb-2">Loading your cart...</h2>
          <p className="text-gray-600 mb-4">Please wait a moment</p>
          <button
            onClick={() => setCurrentPage('products')}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Go Back to Shopping
          </button>
        </div>
      </div>
    );
  }

  // Calculate total
  const total = cart.reduce(
    (sum, item) => {
      const price = Number(item.price) || 0;
      const quantity = Number(item.quantity) || 0;
      return sum + (price * quantity);
    },
    0
  );

  const itemCount = cart.reduce((sum, item) => sum + (Number(item.quantity) || 0), 0);

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-50 via-white to-slate-50">
      {/* HEADER */}
      <header className="bg-white shadow-md sticky top-0 z-40 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 py-4 flex justify-between items-center">
          <button
            onClick={() => setCurrentPage('products')}
            className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-semibold transition-colors"
          >
            <ArrowLeft size={20} />
            <span className="hidden sm:inline">Continue Shopping</span>
            <span className="sm:hidden">Back</span>
          </button>

          <h1 className="text-xl sm:text-2xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
            Shopping Cart
          </h1>

          <button 
            onClick={handleLogout}
            className="p-2 hover:bg-red-50 rounded-lg transition-colors group"
            title="Logout"
          >
            <LogOut className="text-gray-700 group-hover:text-red-600 transition-colors" size={20} />
          </button>
        </div>
      </header>

      {/* CART BODY */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
        {cart.length === 0 ? (
          // Empty Cart State
          <div className="text-center py-16">
            <div className="bg-white rounded-2xl shadow-lg p-12 max-w-md mx-auto">
              <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <ShoppingCart size={48} className="text-blue-500" />
              </div>
              <h2 className="text-2xl font-bold mb-3 text-gray-800">Your cart is empty</h2>
              <p className="text-gray-600 mb-6">Looks like you haven't added anything to your cart yet</p>
              <button 
                onClick={() => setCurrentPage('products')}
                className="px-8 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-xl font-semibold hover:shadow-lg transform hover:scale-105 transition-all duration-300"
              >
                Start Shopping
              </button>
            </div>
          </div>
        ) : (
          // Cart with Items
          <div className="grid lg:grid-cols-3 gap-8">
            {/* CART ITEMS */}
            <div className="lg:col-span-2 space-y-4">
              <div className="bg-white rounded-xl p-4 shadow-sm">
                <h2 className="text-lg font-semibold mb-4">
                  Cart Items ({itemCount} {itemCount === 1 ? 'item' : 'items'})
                </h2>
              </div>

              {cart.map((item, index) => {
                const itemId = item.productIdString || item.productId;
                const imageUrl = item.imageUrl || item.image || 'https://via.placeholder.com/100';
                const productName = item.productName || item.name || 'Unknown Product';
                const price = Number(item.price) || 0;
                const quantity = Number(item.quantity) || 1;
                const brand = item.brand || '';

                console.log(`Rendering cart item ${index}:`, { itemId, productName, quantity, price });

                return (
                  <div 
                    key={itemId || index} 
                    className="bg-white rounded-xl shadow-sm hover:shadow-md transition-shadow p-4 sm:p-6"
                  >
                    <div className="flex gap-4">
                      {/* Product Image */}
                      <div className="flex-shrink-0">
                        <img
                          src={imageUrl}
                          alt={productName}
                          className="w-20 h-20 sm:w-24 sm:h-24 object-cover rounded-lg border border-gray-200"
                          onError={(e) => {
                            e.target.src = 'https://via.placeholder.com/100';
                          }}
                        />
                      </div>

                      {/* Product Details */}
                      <div className="flex-1 min-w-0">
                        <h3 className="font-semibold text-gray-800 mb-1 truncate">
                          {productName}
                        </h3>
                        {brand && (
                          <p className="text-sm text-gray-600 mb-2">{brand}</p>
                        )}
                        <p className="text-lg font-bold text-blue-600 mb-3">
                          ₹{price.toLocaleString()}
                        </p>

                        {/* Quantity Controls */}
                        <div className="flex items-center gap-3">
                          <div className="flex items-center gap-2 bg-gray-100 rounded-lg p-1">
                            <button
                              onClick={() => {
                                console.log('Decreasing quantity for:', itemId);
                                updateCartQuantity(itemId, quantity - 1);
                              }}
                              className="p-2 hover:bg-white rounded-md transition-colors disabled:opacity-50"
                              disabled={quantity <= 1}
                            >
                              <Minus size={16} className="text-gray-700" />
                            </button>

                            <span className="w-12 text-center font-semibold">
                              {quantity}
                            </span>

                            <button
                              onClick={() => {
                                console.log('Increasing quantity for:', itemId);
                                updateCartQuantity(itemId, quantity + 1);
                              }}
                              className="p-2 hover:bg-white rounded-md transition-colors"
                            >
                              <Plus size={16} className="text-gray-700" />
                            </button>
                          </div>

                          <span className="text-sm text-gray-600">
                            = ₹{(price * quantity).toLocaleString()}
                          </span>
                        </div>
                      </div>

                      {/* Remove Button */}
                      <button
                        onClick={() => {
                          console.log('Removing item:', itemId);
                          removeFromCart(itemId);
                        }}
                        className="p-2 hover:bg-red-50 rounded-lg transition-colors group self-start"
                        title="Remove item"
                      >
                        <Trash2 
                          size={20} 
                          className="text-gray-400 group-hover:text-red-600 transition-colors" 
                        />
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* ORDER SUMMARY */}
            <div className="lg:col-span-1">
              <div className="bg-white rounded-xl shadow-lg p-6 sticky top-24">
                <h3 className="text-xl font-bold mb-6 text-gray-800">Order Summary</h3>

                <div className="space-y-3 mb-6">
                  <div className="flex justify-between text-gray-700">
                    <span>Subtotal ({itemCount} items)</span>
                    <span className="font-semibold">₹{total.toLocaleString()}</span>
                  </div>

                  <div className="flex justify-between text-gray-700">
                    <span>Shipping</span>
                    <span className="text-green-600 font-semibold">FREE</span>
                  </div>

                  <div className="border-t pt-3 mt-3">
                    <div className="flex justify-between text-lg font-bold text-gray-800">
                      <span>Total</span>
                      <span className="text-blue-600">₹{total.toLocaleString()}</span>
                    </div>
                  </div>
                </div>

                <button
                  onClick={() => {
                    console.log('Proceeding to checkout');
                    setCurrentPage('checkout');
                  }}
                  className="w-full py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-xl font-semibold hover:shadow-lg transform hover:scale-105 transition-all duration-300"
                >
                  Proceed to Checkout
                </button>

                <button
                  onClick={() => setCurrentPage('products')}
                  className="w-full mt-3 py-3 border-2 border-gray-300 text-gray-700 rounded-xl font-semibold hover:bg-gray-50 transition-colors"
                >
                  Continue Shopping
                </button>

                {user && (
                  <div className="mt-6 p-4 bg-blue-50 rounded-lg">
                    <p className="text-sm text-blue-800">
                      ✓ Logged in as <span className="font-semibold">{user.name || user.email}</span>
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default CartPage;
